local handler = class("GamePacketHandler", EventObservable)

function handler:init()
    self:registerEvent(S2CAddWallText, self.onAddWallText)
end

function handler.onAddWallText(data)
    local result = StringUtil.split(data, ",")
    local text = tostring(result[1])
    local index = tonumber(result[2])
    Utility.addWallText(text, index)
end

return handler